<script>const track=document.getElementById('blog-track'),viewport=document.getElementById('blog-viewport');if(track&&viewport){let index=0,timer;const cards=[...track.children];const visible=()=>innerWidth<=650?1:innerWidth<=950?2:3;const move=()=>{const card=cards[0];if(!card)return;const max=Math.max(0,cards.length-visible());index=Math.min(index,max);track.style.transform=`translateX(-${index*(card.getBoundingClientRect().width+20)}px)`};const next=()=>{const max=Math.max(0,cards.length-visible());index=index>=max?0:index+1;move()};document.getElementById('blog-next')?.addEventListener('click',next);document.getElementById('blog-prev')?.addEventListener('click',()=>{const max=Math.max(0,cards.length-visible());index=index<=0?max:index-1;move()});const start=()=>timer=setInterval(next,5000);const stop=()=>clearInterval(timer);viewport.addEventListener('mouseenter',stop);viewport.addEventListener('mouseleave',start);addEventListener('resize',move);start()}</script>
